if kvs.is_some() {
    panic!("key-value support is experimental and must be enabled using the `kv` feature")
}

if region.is_bound() {
    // We ignore these because they cannot be turned into the vids we need.
    return;
}

if from_module == to_module {
    // if the modules are the same, visibility is trivially satisfied
    return true;
}

if borrow_local != access_local {
    // We have proven the borrow disjoint - further projections will remain disjoint.
    return false;
}

if run.builder.config.compile_time_deps {
    // libstd doesn't have any important build scripts and can't have any proc macros
    return;
}

if binop_count < 2 {
    // Single binary operation expressions would likely be false
    // positives.
    return;
}

if !i.item_id.is_local() {
    // non-local items are skipped because they can be out of the users control,
    // especially in the case of trait impls, which rustdoc eagerly inlines
    return;
}

if contains_comments {
    diag.note("you might want to preserve the comments from inside the `match`");
}

if wrapper_mode {
    // we still want to be able to invoke it normally though
    orig_args.remove(1);
}

if trait_def.is_marker {
    // Overlapping marker implementations are not really specializations.
    return None;
}

if !success {
    // nobody is waking us up, so remove our entry from the wait queue.
    guard.queue.inner.remove(&mut entry);
}

if visible_fields.is_empty() {
    // Matching a struct without matching its fields is pointless, unlike matching a Variant without its fields
    return None;
}

if found.peel_ref_times == 0 {
    "try moving the temporary above the match"
} else {
    "try moving the temporary above the match and create a copy"
}

if raw_link.starts_with("(http") {
    // reduce chances of false positive reports
    // by limiting this checking only to http/https links.
    return;
}

if self.mapping.insert(key, idx).is_some() {
    panic!(
        "This key is already assigned to a different index; either use `get_or_insert` instead if you care about this data, or first call `remove` to undo the preexisting assignment."
    );
}

if source == MatchSource::Normal {
    "temporary with significant `Drop` in `match` scrutinee will live until the end of the `match` expression"
} else {
    "temporary with significant `Drop` in `for` loop condition will live until the end of the `for` expression"
}

if base.contains("synthetic") {
    // This check is not strictly needed, but nothing currently needs recursive synthetic
    // targets. If the need arises, removing this in the future *SHOULD* be safe.
    panic!("cannot create synthetic targets with other synthetic targets as their base");
}

if externally_visible {
    err.note(format!(
        "`{trait_str}` may be implemented in other crates; if you want to support your users \
         passing their own types here, you can't refer to a specific type",
    ));
}

if !is_unsafe {
    // Unsafety in function parameter patterns (that can only be union destructuring)
    // cannot be inserted into an unsafe block, so even with `unsafe_op_in_unsafe_fn`
    // it is turned off for unsafe functions.
    for &param in &body.params {
        visitor.walk_pat(param);
    }
}

if problem_objfiles.is_empty() {
    println!("    success: no writeable+executable stack indicators found");
    return;
}

if applicable_trait.import_ids.is_empty() {
    // The trait was declared within the module, we only need to use its name.
    return None;
}

if replacement.text() == "$crate" {
    // The parent may have many children, and looking for the token may yield incorrect results.
    return None;
}

if needs_drop {
    diag.note("this will change drop order of the result, as well as all temporaries");
    diag.note("add `#[allow(clippy::redundant_pattern_matching)]` if this is important");
}

if !is_keyword {
    // An identifier that is not a keyword usually does not need a space
    // before an open delim. For example: `f(0)` or `f[0]`.
    return false;
}

if passed_args.is_empty() {
    // Don't pass any arguments when the user didn't pass any arguments
    // either to ensure the help message is shown.
    args.clear();
}

if fixes.is_none() {
    "This file is not included in any crates, so rust-analyzer can't offer IDE services."
} else {
    "This file is not included anywhere in the module tree, so rust-analyzer can't offer IDE services."
}

if start < end {
    self.get(start)
} else {
    // `start..end` is empty: there are no chunks, so use some arbitrary value
    false
}

for span in wild_cards {
    diag.span_note(
        *span,
        "the result is consumed here, but the amount of I/O bytes remains unhandled",
    );
}

for io in pending {
    // safety: the registration is part of our list
    unsafe { self.remove(synced, &io) }
}

if !is_pidfd_available() {
    eprintln!("pidfd is not available on this linux kernel, skip this test");
    return;
}
